import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10; // Size of the buffer
        char[] buffer = new char[bufferSize]; // Buffer with fixed size

        if (input.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
        } else {
            input.getChars(0, input.length(), buffer, 0); // Copy input into buffer

            System.out.println("Buffer content: " + new String(buffer));
        }

        scanner.close();
    }
}

### Explanation:
